import{_ as s,o as a,c as e,a2 as l}from"./chunks/framework.BflysNKA.js";const k=JSON.parse('{"title":"排障手册","description":"","frontmatter":{},"headers":[],"relativePath":"support/troubleshooting.md","filePath":"support/troubleshooting.md","lastUpdated":1778577020000}'),t={name:"support/troubleshooting.md"};function n(d,i,o,h,p,r){return a(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="排障手册" tabindex="-1">排障手册 <a class="header-anchor" href="#排障手册" aria-label="Permalink to &quot;排障手册&quot;">​</a></h1><p>终端或客户端报错时，按下面顺序排查。每次只改一项，便于定位问题。</p><h2 id="先记住各工具最容易填错的地址" tabindex="-1">先记住各工具最容易填错的地址 <a class="header-anchor" href="#先记住各工具最容易填错的地址" aria-label="Permalink to &quot;先记住各工具最容易填错的地址&quot;">​</a></h2><p>同一个网关，不同工具的地址要求并不完全一样。排障前先把这一层分清楚，能省掉很多时间。</p><table tabindex="0"><thead><tr><th>工具</th><th>正确地址</th><th>最常见填错方式</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>https://xiaolan1.cn</code></td><td>误写成 <code>https://xiaolan1.cn/v1</code></td></tr><tr><td>Gemini CLI</td><td><code>https://xiaolan1.cn</code></td><td>误写成 <code>https://xiaolan1.cn/v1</code></td></tr><tr><td>Cherry Studio</td><td><code>https://xiaolan1.cn</code></td><td>误写成 <code>https://xiaolan1.cn/v1</code></td></tr><tr><td>Codex / OpenAI SDK / 大多数 OpenAI 兼容工具</td><td><code>https://xiaolan1.cn/v1</code></td><td>误写成根地址 <code>https://xiaolan1.cn</code></td></tr></tbody></table><p>连第一步该查地址还是查 Key 都不确定时，先对照这一张表。</p><h2 id="先判断卡在哪一层" tabindex="-1">先判断卡在哪一层 <a class="header-anchor" href="#先判断卡在哪一层" aria-label="Permalink to &quot;先判断卡在哪一层&quot;">​</a></h2><p>很多问题不是“工具坏了”，而是卡在不同层级。先判断层级，再动手改配置，速度会快很多。</p><table tabindex="0"><thead><tr><th>层级</th><th>典型现象</th><th>先看哪里</th></tr></thead><tbody><tr><td>安装层</td><td><code>node</code>、<code>npm</code>、<code>git</code>、<code>claude</code>、<code>codex</code> 命令不存在</td><td>先回 <a href="/node/windows">Node 安装</a> / <a href="/node/macos">macOS Node 安装</a></td></tr><tr><td>配置层</td><td>命令能启动，但鉴权失败、地址错误、模型列表为空</td><td>Base URL、API Key、模型名、配置文件</td></tr><tr><td>网关层</td><td>curl 直接返回 401 / 404 / 429 / 503</td><td>Key 状态、余额、分组、模型权限、当前负载</td></tr><tr><td>模型层</td><td>页面能打开、请求能发出，但回答慢或效果不对</td><td>当前模型、上下文大小、是否换轻量模型验证</td></tr></tbody></table><p>先把问题归类清楚，通常就能知道该先改命令环境、先改配置，还是先回控制台查 Key 和模型。</p><h2 id="步骤-0-确认全局设施状态" tabindex="-1">步骤 0：确认全局设施状态 <a class="header-anchor" href="#步骤-0-确认全局设施状态" aria-label="Permalink to &quot;步骤 0：确认全局设施状态&quot;">​</a></h2><p>先确认是否为全局可用性问题：</p><ul><li><strong><a href="https://xiaolan1.cn/api/status" target="_blank" rel="noreferrer">官方状态探针</a></strong>：看看 小蓝中转站 网关当前是否大面积故障。</li><li><strong>模型广场</strong>：确认目标模型是否处于维护中或暂时下线。</li></ul><h2 id="步骤-1-http-状态码" tabindex="-1">步骤 1：HTTP 状态码 <a class="header-anchor" href="#步骤-1-http-状态码" aria-label="Permalink to &quot;步骤 1：HTTP 状态码&quot;">​</a></h2><p>遇到报错，先看返回的状态码：</p><p>已经看到了明确的 <code>401</code>、<code>404</code>、<code>429</code> 这类状态码时，说明请求通常已经成功发到了网关。这个时候继续重装 Node.js、Git 或客户端，收益往往不大，优先查 Key、模型名、分组和余额更直接。</p><h3 id="❌-400-bad-request" tabindex="-1">❌ 400 Bad Request <a class="header-anchor" href="#❌-400-bad-request" aria-label="Permalink to &quot;❌ 400 Bad Request&quot;">​</a></h3><ul><li>模型名拼写错误。请从模型广场复制完整名称。</li><li>这把 Key 的权限组不包含这个模型。</li><li>请求内容格式不符合接口要求。</li><li>工具和网关协议不匹配，例如本应走 OpenAI 兼容，却写成了别的协议路径。</li></ul><h3 id="🚫-401-unauthorized" tabindex="-1">🚫 401 Unauthorized <a class="header-anchor" href="#🚫-401-unauthorized" aria-label="Permalink to &quot;🚫 401 Unauthorized&quot;">​</a></h3><ul><li>你的 <code>API Key</code> 填错了，或者没带 <code>sk-</code> 前缀。</li><li>这把 Key 已被禁用，或触发控制台额度上限。</li><li>当前终端根本没有读到你刚写入的环境变量。</li></ul><h3 id="🚧-403-forbidden" tabindex="-1">🚧 403 Forbidden <a class="header-anchor" href="#🚧-403-forbidden" aria-label="Permalink to &quot;🚧 403 Forbidden&quot;">​</a></h3><p>通常是被网关安全策略拦截：</p><ul><li>你的请求 Header 不规范。</li><li>遇到了严格的风控阻断。</li></ul><h3 id="🔎-404-not-found-model-not-found" tabindex="-1">🔎 404 Not Found / Model Not Found <a class="header-anchor" href="#🔎-404-not-found-model-not-found" aria-label="Permalink to &quot;🔎 404 Not Found / Model Not Found&quot;">​</a></h3><ul><li>模型名不存在。</li><li>模型名来自旧教程或官方示例，不是模型广场里的名称。</li><li>当前 Key 看不到这个模型。</li><li>地址层已经写错，例如 Claude Code / Gemini CLI / Cherry Studio 手动补了 <code>/v1</code>，或 Codex 少了 <code>/v1</code>。</li></ul><p>处理方式：回<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a>复制完整模型名。</p><h3 id="🚦-429-too-many-requests" tabindex="-1">🚦 429 Too Many Requests <a class="header-anchor" href="#🚦-429-too-many-requests" aria-label="Permalink to &quot;🚦 429 Too Many Requests&quot;">​</a></h3><ul><li>请求太密集。</li><li>当前 Key 或模型触发频率限制。</li><li>自动化脚本并发过高。</li></ul><p>处理方式：降低并发、加重试间隔、先换轻量模型验证。</p><h3 id="⏳-503-504-响应极慢" tabindex="-1">⏳ 503 / 504 / 响应极慢 <a class="header-anchor" href="#⏳-503-504-响应极慢" aria-label="Permalink to &quot;⏳ 503 / 504 / 响应极慢&quot;">​</a></h3><ul><li>模型后端可能处于高负载状态。</li><li>先换轻量模型确认网络和 Key 正常。</li><li>清理无关上下文，减少单次请求体积。</li></ul><h2 id="步骤-2-环境连通性自检-ping" tabindex="-1">步骤 2：环境连通性自检 (Ping) <a class="header-anchor" href="#步骤-2-环境连通性自检-ping" aria-label="Permalink to &quot;步骤 2：环境连通性自检 (Ping)&quot;">​</a></h2><p>Claude Code、Gemini CLI 这类终端工具一直连不上时，打开一个新的终端窗口，输入以下命令进行最小化验证：</p><p>先把 <code>MODEL</code> 替换成你在模型广场复制的一个轻量模型名：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;替换成模型广场里的轻量模型名&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/chat/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer sk-你的专属Key&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;{</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">model</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">$MODEL</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">messages</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:[{</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">role</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">user</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">content</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">}]}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>如果能收到带回复的 JSON，说明 小蓝中转站 网关、Key 和网络连通性正常。继续检查本地工具配置。</p><ul><li><strong>curl 也失败</strong>：先解决网关、Key、模型或网络问题</li><li><strong>curl 成功，客户端失败</strong>：说明问题更可能在本地工具配置，而不是 小蓝中转站 本身</li></ul><p>先用最小请求证明链路通不通，通常比反复重装客户端更快。</p><h2 id="步骤-3-本地环境自检" tabindex="-1">步骤 3：本地环境自检 <a class="header-anchor" href="#步骤-3-本地环境自检" aria-label="Permalink to &quot;步骤 3：本地环境自检&quot;">​</a></h2><p>终端工具先查基础环境：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>期望：</p><ul><li><code>node</code> 有版本号</li><li><code>npm</code> 有版本号</li><li><code>git</code> 有版本号</li><li>npm registry 是 <code>https://registry.npmmirror.com/</code></li></ul><p>缺 Node 或 Git 时，按系统回 <a href="/node/windows">Windows Node 安装</a>、<a href="/node/macos">macOS Node 安装</a> 或 <a href="/node/linux">Linux Node 安装</a> 补环境。</p><p>现在连工具都还没装上时，不要急着排接口。先把安装入口和基础命令理顺：</p><ul><li>Windows Node.js：优先 <code>nodejs.cn/download</code></li><li>Windows Git：优先 <code>winget install --id Git.Git -e --source winget</code></li><li>macOS Git：优先 <code>xcode-select --install</code></li><li>CC-Switch：优先 <a href="https://ccswitch.ai/zh/" target="_blank" rel="noreferrer">https://ccswitch.ai/zh/</a></li><li>Cherry Studio：优先 <a href="https://docs.cherry-ai.com/cherry-studio/download" target="_blank" rel="noreferrer">https://docs.cherry-ai.com/cherry-studio/download</a></li></ul><h2 id="步骤-4-工具配置自检" tabindex="-1">步骤 4：工具配置自检 <a class="header-anchor" href="#步骤-4-工具配置自检" aria-label="Permalink to &quot;步骤 4：工具配置自检&quot;">​</a></h2><h3 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_AUTH_TOKEN</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Claude Code 这里应看到根地址 <code>https://xiaolan1.cn</code>，不是 <code>/v1</code> 地址。</p><p>还想再确认一层时，可以继续看：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_MODEL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>常见判断：</p><ul><li><code>ANTHROPIC_BASE_URL</code> 正确，但还是连不上：继续看 <code>ANTHROPIC_AUTH_TOKEN</code></li><li>地址和 Key 都正确，但 <code>/model</code> 列表空：继续看分组和模型权限</li><li>模型能看到，但当前回复不对：继续看 <code>ANTHROPIC_MODEL</code> 或当前会话实际选中的模型</li></ul><h3 id="codex" tabindex="-1">Codex <a class="header-anchor" href="#codex" aria-label="Permalink to &quot;Codex&quot;">​</a></h3><p>Codex 优先检查本地配置文件和 Key 环境变量，不先看 <code>OPENAI_BASE_URL</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.codex/config.toml</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $小蓝中转站_API_KEY</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>重点确认：</p><ul><li><code>base_url = &quot;https://xiaolan1.cn/v1&quot;</code></li><li><code>wire_api = &quot;responses&quot;</code></li><li><code>env_key = &quot;小蓝中转站_API_KEY&quot;</code></li><li>当前终端里 <code>小蓝中转站_API_KEY</code> 真的有值</li></ul><p>以前用过官方登录时，<code>~/.codex/auth.json</code> 可能已经存在。<br> 但当前这套 小蓝中转站 接法主要看的不是它，而是 <code>config.toml</code> 和 <code>小蓝中转站_API_KEY</code>。</p><p>怀疑当前项目覆盖了用户级配置时，再检查一次：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ./.codex/config.toml</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>项目目录里如果有另一份 <code>.codex/config.toml</code>，它可能会覆盖主目录里的默认值。</p><h3 id="gemini-cli" tabindex="-1">Gemini CLI <a class="header-anchor" href="#gemini-cli" aria-label="Permalink to &quot;Gemini CLI&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $GOOGLE_GEMINI_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $GEMINI_API_KEY</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $GEMINI_MODEL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Gemini CLI 这里应看到根地址 <code>https://xiaolan1.cn</code>，不要手动补 <code>/v1</code>。当前版本会自己继续拼接 <code>/v1beta/models/...</code> 这类 Gemini API 路径。</p><p>如果地址和 Key 都正确，但当前模型不像你刚配置的那个，可以继续试两步：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">gemini</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> 从模型广场复制的模型名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>进入 Gemini CLI 后再输入：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>/model</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果临时指定模型能生效，而平时默认值不生效，优先检查当前目录里是不是还有额外的 <code>.gemini</code> 配置覆盖掉了默认设置。</p><p>如果 Gemini CLI 还没安装完成，先决定你要用哪种方式：</p><ul><li>临时试用：<code>npx @google/gemini-cli</code></li><li>长期使用：<code>npm install -g @google/gemini-cli</code></li><li>官方仓库：<a href="https://github.com/google-gemini/gemini-cli" target="_blank" rel="noreferrer">https://github.com/google-gemini/gemini-cli</a></li></ul><p>Windows PowerShell 把 <code>$变量名</code> 换成 <code>$env:变量名</code>。</p><h3 id="opencode" tabindex="-1">OpenCode <a class="header-anchor" href="#opencode" aria-label="Permalink to &quot;OpenCode&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> ~/.config/opencode/opencode.json</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $小蓝中转站_API_KEY</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">opencode</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> list</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>优先检查：</p><ul><li><code>provider</code> 里是否写了 <code>baseURL = &quot;https://xiaolan1.cn/v1&quot;</code></li><li><code>model</code> / <code>small_model</code> 前缀是否和 Provider 名一致</li><li>你现在走的是环境变量方案，还是 <code>/connect</code> 保存的认证方案</li></ul><p>走的是 <code>/connect</code> 路线时，<code>opencode auth list</code> 比盯着旧的 <code>OPENAI_API_KEY</code> 变量更直接。</p><h3 id="cherry-studio" tabindex="-1">Cherry Studio <a class="header-anchor" href="#cherry-studio" aria-label="Permalink to &quot;Cherry Studio&quot;">​</a></h3><p>先回到服务商设置页看这几项：</p><ul><li>服务商类型是否是 OpenAI 兼容</li><li>API 地址是否是 <code>https://xiaolan1.cn</code></li><li>保存后有没有点过 <code>Check</code></li><li>模型列表有没有重新拉取</li></ul><p>Cherry Studio 官方当前会自己继续拼接 OpenAI 兼容路径，所以它的 API 地址栏更适合填根地址 <code>https://xiaolan1.cn</code>，不是 <code>https://xiaolan1.cn/v1</code>。</p><p>已经拉到了模型列表，但发消息时还是报模型不存在，就先看两件事：</p><ol><li>当前新对话实际选中的，是不是刚配置的 小蓝中转站 服务商</li><li>当前下拉框里选中的，是不是刚拉下来的那个模型</li></ol><h2 id="步骤-5-缩小问题范围" tabindex="-1">步骤 5：缩小问题范围 <a class="header-anchor" href="#步骤-5-缩小问题范围" aria-label="Permalink to &quot;步骤 5：缩小问题范围&quot;">​</a></h2><p>按这个顺序换：</p><ol><li>换轻量模型。</li><li>换一把新 Key。</li><li>换一个新终端窗口。</li><li>换手机热点。</li><li>换客户端。</li></ol><p>每次只换一项。一次改太多，定位不了问题。</p><p>连“安装失败”和“配置失败”都分不清时，先把问题拆开：</p><ol><li>先确认工具有没有装上：<code>claude --version</code> / <code>codex --version</code> / <code>gemini --version</code></li><li>再确认环境变量或配置文件有没有写对</li><li>最后再测网关、Key 和模型</li></ol><p>先把“命令能启动”解决，再去查接口问题，速度会快很多。</p><h2 id="联系支持" tabindex="-1">联系支持 <a class="header-anchor" href="#联系支持" aria-label="Permalink to &quot;联系支持&quot;">​</a></h2><p>带上以下信息，前往 <a href="/support/after-sales">售前与售后支持</a>：</p><ol><li>遇到报错的工具名称（比如：Alma 或 Claude Code）。</li><li>终端里完整的报错日志原文。</li><li>你的本地配置截图（<strong>务必打码掩盖你的完整 Key 字符串</strong>）。</li><li>最小 curl 测试结果。</li><li>你使用的模型名。</li></ol>`,95)])])}const u=s(t,[["render",n]]);export{k as __pageData,u as default};
